+use std::collections::HashMap;
+use crate::opcodes;
+
+pub struct CPU{
+    pub register_a: u8,
+    pub register_x: u8,
+    pub status: u8,
+    pub program_counter: u16,
+    memory: [u8;0xFFFF]
+}
+
+
+#[derive(Debug)]
+#[allow(non_camel_case_types)]
+pub enum AddressingMode{
+    Immediate,
+    ZeroPage,
+    ZeroPageX,
+    Absolute,
+    AbsoluteX,
+    AbsoluteY,
+    Indirect_X,
+    Indirect_Y,
+    NonAddressing,
+}
+
+trait Mem{
+    fn mem_read(&self,addr:u16)->u8;
+
+    fn mem_write(&self,addr:u16,data:u8);
+
+    fn mem_read_u16(&self,pos:u16)->u16{
+        let lo=self.mem_read(pos) as u16;
+        let hi=self.mem_read(pos+1) as u16;
+        (hi << 8) | (lo as u16)
+    }
+
+    fn mem_write_u16(&self,pos:u16,data:u16){
+        let hi=(data>>8) as u8;
+        let lo=(data&0xff) as u8;
+        self.mem_write(pos,lo);
+        self.mem_write(pos+1,hi);
+    }
+}
+
+impl Mem for CPU{
+    fn mem_read(&self,addr:u16)->u8{
+        self.memory[addr as usize]
+    }
+
+    fn mem_write(&self,addr:u16,data:u8){
+        self.memory[addr as usize] = data;
+    }
+
+}
+
+impl CPU{
+    pub fn new()->Self{
+        CPU{
+            register_a: 0,
+            register_x: 0,
+            status: 0,
+            program_counter: 0,
+            memory: [0;0xFFFF]
+        }
+    }
+    // @trace-pilot 3ca989c2e44450ce559d012cc2ec87b0add0268d
+    //$A9
+    fn lda(&mut self,value: u8){
+        self.register_a=value;
+        self.update_zero_and_negative_flags(self.register_a);
+    }
+
+    // @trace-pilot 14f89bddf5170ccd3c07d8ea8ca6f2a20ba704b4
+    //$AA
+    fn tax(&mut self){
+        self.register_x=self.register_a;
+        self.update_zero_and_negative_flags(self.register_x);
+    }
+
+    fn update_zero_and_negative_flags(&mut self,result: u8){
+        if result==0{
+            self.status=self.status|0b0000_0010;
+        }else{
+            self.status=self.status&0b1111_1101;
+        }
+
+        if result&0b1000_000!=0{
+            self.status=self.status|0b1000_0000;
+        }else{
+            self.status=self.status&0b0111_1111;
+        }
+    }
+
+    // @trace-pilot 91288bb1da780a9fa7f059008e6681e983d042b5
+    //$E8
+    fn inx(&mut self){
+        // @trace-pilot aa029cb684e68087f172f3c8c320be1bcf5b9afa
+        //wrapping_add(1) = オーバーフローしても循環する加算
+        self.register_x=self.register_x.wrapping_add(1);
+        self.update_zero_and_negative_flags(self.register_x);
+    }
+
+    pub fn interpret(&mut self,program: Vec<u8>){
+        self.program_counter=0;
+        loop{
+            let opscode=program[self.program_counter as usize];
+            self.program_counter +=1;
+
+            match opscode{
+                0xA9=>{
+                    let param=program[self.program_counter as usize];
+                    self.program_counter+=1;
+
+                    self.lda(param);
+                }
+
+                0xAA=>self.tax(),
+
+                0xe8=>self.inx(),
+
+                0x00=>return,
+
+                _=>todo!(),
+            }
+        }
+    }
+
+}
+
+#[cfg(test)]
+mod test{
+    use super::*;
+
+    #[test]
+    fn test_0xa9_lda_immediate_load_data(){
+        let mut cpu=CPU::new();
+        // LDA #$05
+        // BRK
+        cpu.interpret(vec![0xa9,0x05,0x00]);
+        assert_eq!(cpu.register_a,5);
+        assert!(cpu.status & 0b0000_0010==0);
+        assert!(cpu.status & 0b1000_0000==0);
+    }
+
+    #[test]
+    fn test_0xa9_lda_zero_flag(){
+        let mut cpu=CPU::new();
+        cpu.interpret(vec![0xa9,0x00,0x00]);
+        assert!(cpu.status & 0b0000_0010==0b10);
+    }
+
+    #[test]
+    fn test_0xa9_lda_negative_flat(){
+        let mut cpu=CPU::new();
+        cpu.interpret(vec![0xa9,0xff,0x00]);
+        assert!(cpu.status & 0b1000_0000==0b1000_0000);
+    }
+
+    #[test]
+    fn test_0xaa_tax_move_a_to_x(){
+        let mut cpu=CPU::new();
+        cpu.register_a=10;
+        cpu.interpret(vec![0xaa,0x00]);
+        assert_eq!(cpu.register_x,10);
+    }
+
+    #[test]
+    fn test_5_ops_working_together(){
+        let mut cpu=CPU::new();
+        /*
+         * LDA #$0xc0
+         * TAX
+         * INX
+         * BRK
+         */
+        cpu.interpret(vec![0xa9,0xc0,0xaa,0xe8,0x00]);
+        assert_eq!(cpu.register_x,0xc1);
+    }
+
+    #[test]
+    fn test_inx_overflow(){
+        let mut cpu=CPU::new();
+        cpu.register_x=0xff;
+        cpu.interpret(vec![0xe8,0xe8,0x00]);
+        assert_eq!(cpu.register_x,1);
+    }
+}

